  ('aboriginal-d0d1b9a2-moex-00028', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X5年4月1日以$1,081,696之價格發行面額$1,000,000、利率5%、10年期公司債，每 年4月1日及10月1日付息，發行當日市場利率為4%。甲公司為曆年制，採有效利率法攤銷溢 折價，則甲公司X5年應認列利息費用是多少？（四捨五入至整數位）', '["$32,417", "$37,500", "$42,583", "$43,201"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00029', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '下列各項中，有幾項屬於籌資活動之現金流量？①收取現金股利  ②舉借債務  ③出售交易目的', '["透過其他綜合損益按公允價值衡量之債券投資評價損益 ⑤再出售庫藏股票  ⑥採權益法認列之投資損失", "1項", "2項", "3項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00030', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司X5年期初應收帳款$66,000，期末應收帳款$68,000，期初應付帳款$50,000，期末應付帳款 $58,000，期初存貨$126,000，期末存貨$130,000，本期銷貨成本$1,900,000，則甲公司X5年度進 貨付現金額是多少？', '["$1,888,000", "$1,896,000", "$1,904,000", "$1,912,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00031', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司X5年發生下列交易：添購設備支付$160,000；借款給關係企業$100,000；出售一筆帳面金 額為$900,000土地，獲利$45,000；出售交易目的持有之金融資產，帳面金額$80,000，損失$6,500； 增資發行新股$300,000。則甲公司X5年現金流量表中投資活動之現金流量為多少？', '["淨現金流入$685,000", "淨現金流入$758,500", "淨現金流入$958,500", "淨現金流入$1,205,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00032', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '若公司淨資產為正數，下列何項會導致公司之負債對資產比率增加？', '["發放股票股利", "支付應付利息", "處分設備產生損失", "收回公司債產生利得"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00033', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '下列何者應列為「追溯適用及追溯重編影響數」？', '["改變折舊資產之折舊方法", "建造合約在變成可合理衡量進度後改採用「完工比例法」", "改變無形資產耐用年限之評估", "會計原則適用錯誤"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00034', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司之X5年9月薪資費用為$44,000。X5年8月31日應付薪資餘額為$7,980，9月30日應付 薪資餘額為$8,730，試問X5年9月實際支付之薪資現金為何？', '["$35,270", "$43,250", "$44,750", "$51,980"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00035', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司自設立以來即採用先進先出法計算存貨成本。X4 年之期末存貨為$65,000；若採用個別認 定法則期末存貨應為$47,000。假設X4年改用個別認定法，甲公司之稅前淨利：', '["在過去年度累計將增加$18,000", "在過去年度累計將減少$18,000", "於X4年將增加$18,000", "於X4年將減少$18,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00036', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司之X4與X3年財務報表存在下列錯誤： X4年：期末存貨高估$4,000；折舊費用低估$3,500。 X3年：期末存貨低估$6,000；折舊費用高估$5,000。 假設X3年12月31日未作任何更正分錄，且忽略所得稅，則X4年12月31日之保留盈餘將被 高估或低估多少？', '["高估$2,500", "低估$2,500", "高估$5,000", "低估$9,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00037', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司之存貨處理係採用定期盤存制。X4年度資料如下：期初存貨3,000單位，單位成本$50；5 月20日進貨6,000單位，單位成本$40；10月8日進貨3,000單位，單位成本$30。期末盤點存貨 尚餘2,400單位。若存貨流動假設為平均法，則X4年銷貨成本為何？', '["$372,000", "$384,000", "$396,000", "$408,000 60740"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL)
